import React, { useEffect, useState } from 'react';
import { View, Text, StyleSheet, ScrollView, TouchableOpacity, ActivityIndicator, FlatList } from 'react-native';
import { LinearGradient } from 'expo-linear-gradient';
import { supabase } from './supabaseClient'; // Asegúrate de importar correctamente el cliente de Supabase

interface JourneyMission {
  id: string;
  created_at: string;
  completed: boolean;
  journeyId: string;
  challengeId: string;
  userId: string | null;
  journeys: {
    description: string;
  };
  challenges: {
    title: string;
    description: string;
  };
  user: string | null;
}

const MissionsScreen = () => {
  const [journeyMissions, setJourneyMissions] = useState<Map<string, JourneyMission[]>>(new Map());
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [updatingMission, setUpdatingMission] = useState<string | null>(null);
  const [username, setUsername] = useState<string>('');  // Aquí guardaremos el username del usuario
  const [selectedJourneyId, setSelectedJourneyId] = useState<string | null>(null);

  useEffect(() => {
    const fetchUserData = async () => {
      const user = supabase.auth.user(); // Obtener el usuario autenticado de Supabase

      if (user) {
        setUsername(user.user_metadata.username || 'Usuario Anónimo');  // Obtener el username
      } else {
        setError('No se pudo obtener la información del usuario');
      }

      setLoading(false);
    };

    fetchUserData();
  }, []);  // El useEffect se ejecuta una vez cuando el componente se monta

  useEffect(() => {
    const fetchUserMissions = async () => {
      const user = supabase.auth.user();
      if (!user?.id) return;

      try {
        const response = await fetch(`http://localhost:5000/api/journeysMissions/user/${user.id}`);
        const data = await response.json();

        if (!response.ok) {
          throw new Error('Error al obtener las misiones');
        }

        console.log('Misiones del usuario:', data);

        // Agrupar misiones por journeyId
        const groupedMissions = data.reduce((acc: Map<string, JourneyMission[]>, mission: JourneyMission) => {
          if (!acc.has(mission.journeyId)) {
            acc.set(mission.journeyId, []);
          }
          acc.get(mission.journeyId)?.push(mission);
          return acc;
        }, new Map<string, JourneyMission[]>());

        setJourneyMissions(groupedMissions);
      } catch (err: any) {
        console.error('Error al obtener las misiones:', err.message);
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchUserMissions();
  }, []);

  const handleCompleteMission = async (missionId: string) => {
    try {
      setUpdatingMission(missionId);
      // Aquí puedes agregar la lógica para actualizar la misión, por ejemplo, hacer un PUT o PATCH a la API
    } catch (err: any) {
      console.error('Error al completar la misión:', err.message);
    } finally {
      setUpdatingMission(null);
    }
  };

  const handleSelectJourney = (journeyId: string) => {
    // Cambiar el journey seleccionado para mostrar sus misiones
    if (selectedJourneyId === journeyId) {
      setSelectedJourneyId(null); // Si ya está seleccionado, lo deseleccionamos
    } else {
      setSelectedJourneyId(journeyId);
    }
  };

  if (loading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#0000ff" />
        <Text>Cargando...</Text>
      </View>
    );
  }

  if (error) {
    return (
      <View style={styles.container}>
        <Text style={styles.errorText}>{error}</Text>
      </View>
    );
  }

  return (
    <ScrollView style={styles.container}>
      <LinearGradient
        colors={['#4CAF50', '#2E7D32']}
        style={styles.header}
      >
        <Text style={styles.headerTitle}>Misiones de Viaje</Text>
        <Text style={styles.headerSubtitle}>¡Completa tus desafíos, {username}!</Text> {/* Aquí mostramos el username */}
      </LinearGradient>

      {Array.from(journeyMissions.keys()).map((journeyId) => (
        <View key={journeyId} style={styles.journeyCard}>
          <TouchableOpacity onPress={() => handleSelectJourney(journeyId)}>
            <LinearGradient
              colors={['#ffffff', '#f8f8f8']}
              style={styles.cardGradient}
            >
              <Text style={styles.journeyTitle}>{journeyMissions.get(journeyId)?.[0].journeys?.description || 'Viaje no disponible'}</Text> {/* Aquí mostramos la descripción del viaje */}
            </LinearGradient>
          </TouchableOpacity>

          {selectedJourneyId === journeyId && (
            <FlatList
              data={journeyMissions.get(journeyId)}
              renderItem={({ item: mission }) => (
                <View style={styles.missionCard}>
                  <LinearGradient
                    colors={['#ffffff', '#f8f8f8']}
                    style={styles.cardGradient}
                  >
                    <View style={styles.cardHeader}>
                      <View style={styles.titleContainer}>
                        <Text style={styles.missionTitle}>{mission.challenges?.title || 'Sin título'}</Text>
                        <Text style={[
                          styles.statusBadge,
                          mission.completed ? styles.statusCompleted : styles.statusPending
                        ]}>
                          {mission.completed ? '✓ Completada' : '⏳ Pendiente'}
                        </Text>
                      </View>
                      <Text style={styles.dateText}>
                        {new Date(mission.created_at).toLocaleDateString()}
                      </Text>
                    </View>

                    <View style={styles.detailsContainer}>
                      <View style={styles.detailSection}>
                        <Text style={styles.sectionTitle}>Descripción del Viaje</Text>
                        <Text style={styles.detailValue}>{mission.journeys?.description || 'Sin descripción'}</Text>
                      </View>

                      <View style={styles.detailSection}>
                        <Text style={styles.sectionTitle}>Descripción del Desafío</Text>
                        <Text style={styles.detailValue}>{mission.challenges?.description || 'Sin descripción'}</Text>
                      </View>

                      <View style={styles.userInfo}>
                        <Text style={styles.userLabel}>Usuario:</Text>
                        <Text style={styles.userValue}>{mission.user || username}</Text> {/* Aquí mostramos el username */}
                      </View>
                    </View>

                    {!mission.completed && (
                      <TouchableOpacity 
                        style={styles.completeButton}
                        onPress={() => handleCompleteMission(mission.id)}
                        disabled={updatingMission === mission.id}
                      >
                        {updatingMission === mission.id ? (
                          <ActivityIndicator size="small" color="#FFFFFF" />
                        ) : (
                          <Text style={styles.completeButtonText}>Completar Misión</Text>
                        )}
                      </TouchableOpacity>
                    )}
                  </LinearGradient>
                </View>
              )}
              keyExtractor={(item) => item.id}
            />
          )}
        </View>
      ))}
      <View style={styles.bottomPadding} />
    </ScrollView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#f5f5f5',
  },
  header: {
    padding: 24,
    paddingTop: 40,
    borderBottomLeftRadius: 30,
    borderBottomRightRadius: 30,
    marginBottom: 20,
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 4 },
    shadowOpacity: 0.2,
    shadowRadius: 8,
    elevation: 5,
  },
  headerTitle: {
    fontSize: 28,
    fontWeight: 'bold',
    color: '#FFFFFF',
    textAlign: 'center',
    marginBottom: 8,
  },
  headerSubtitle: {
    fontSize: 16,
    color: '#FFFFFF',
    textAlign: 'center',
    opacity: 0.9,
  },
  journeyCard: {
    marginHorizontal: 16,
    marginBottom: 16,
    borderRadius: 16,
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.1,
    shadowRadius: 8,
    elevation: 3,
  },
  cardGradient: {
    borderRadius: 16,
    padding: 16,
  },
  journeyTitle: {
    fontSize: 18,
    fontWeight: 'bold',
    color: '#2E7D32',
  },
  missionCard: {
    marginBottom: 16,
    borderRadius: 16,
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.1,
    shadowRadius: 8,
    elevation: 3,
  },
  missionTitle: {
    fontSize: 16,
    fontWeight: 'bold',
    color: '#2E7D32',
  },
  statusBadge: {
    fontSize: 12,
    fontWeight: '600',
    paddingHorizontal: 12,
    paddingVertical: 6,
    borderRadius: 20,
    overflow: 'hidden',
  },
  statusCompleted: {
    backgroundColor: '#E8F5E9',
    color: '#2E7D32',
  },
  statusPending: {
    backgroundColor: '#FFF3E0',
    color: '#EF6C00',
  },
  dateText: {
    fontSize: 12,
    color: '#666',
  },
  detailsContainer: {
    backgroundColor: '#FFFFFF',
    borderRadius: 12,
    padding: 16,
  },
  detailSection: {
    marginBottom: 16,
  },
  sectionTitle: {
    fontSize: 14,
    fontWeight: '600',
    color: '#666',
    marginBottom: 8,
  },
  detailValue: {
    fontSize: 14,
    color: '#333',
    lineHeight: 20,
  },
  userInfo: {
    flexDirection: 'row',
    alignItems: 'center',
    marginTop: 8,
    paddingTop: 8,
    borderTopWidth: 1,
    borderTopColor: '#eee',
  },
  userLabel: {
    fontSize: 14,
    color: '#666',
    marginRight: 8,
  },
  userValue: {
    fontSize: 14,
    color: '#333',
    fontWeight: '500',
  },
  completeButton: {
    backgroundColor: '#4CAF50',
    padding: 16,
    borderRadius: 12,
    marginTop: 16,
    alignItems: 'center',
    shadowColor: '#4CAF50',
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.3,
    shadowRadius: 4,
    elevation: 4,
  },
  completeButtonText: {
    color: 'white',
    fontSize: 16,
    fontWeight: '600',
  },
  bottomPadding: {
    height: 20,
  },
  text: {
    fontSize: 16,
    color: '#333',
    textAlign: 'center',
  },
  errorText: {
    fontSize: 16,
    color: '#D32F2F',
    textAlign: 'center',
    padding: 16,
  },
});

export default MissionsScreen;
